SELECT COUNT(*) AS mandatory_resources_count
FROM course_resources
WHERE is_mandatory = 1;

SELECT AVG(weightage) AS average_weightage
FROM weekly_learning_outcomes
WHERE week_id = 1;

SELECT COUNT(*) AS total_mandatory_materials
FROM readings_materials
WHERE is_mandatory = 1;

SELECT resource_name, file_path
FROM course_resources
WHERE is_mandatory = 1 AND week_id = 2;

SELECT week_id, COUNT(outcome_id) AS outcome_count
FROM weekly_learning_outcomes
GROUP BY week_id;

SELECT outcome_description, weightage
FROM weekly_learning_outcomes
ORDER BY weightage DESC;

SELECT student_id, COUNT(resource_id) AS total_accesses, MAX(access_date) AS last_access_date
FROM student_resources
GROUP BY student_id;
